import 'package:flutter/material.dart';

/// Detail level shown in the calendar header panel.
enum BTCalendarDetailState { date, month, year }

/// Time display variant for [BTTimePicker].
enum BTCalendarTimeVariant {
  /// HH:MM (24-hour).
  hhMm,

  /// HH:MM:SS (24-hour with seconds).
  hhMmSs,

  /// H:MM AM/PM (12-hour).
  amPm,

  /// H:MM:SS AM/PM (12-hour with seconds).
  amPmSs,
}

/// Presentation style for the `show*()` factory methods on [BTCalendar]
/// and [BTTimePicker].
enum BTCalendarShowType {
  /// Centred dialog overlay (default).
  modal,

  /// Sliding bottom-sheet drawer.
  drawer,
}

/// Layout style for the built-in preset chips row in [BTCalendar].
enum BTCalendarPresetsType {
  /// Single horizontally-scrollable row, no background.
  scroll,

  /// Wrapping chips with a [bg.secondary] background panel.
  wrap,
}

/// A labelled shortcut that resolves to a [DateTime] at call time.
class BTCalendarPreset {
  const BTCalendarPreset({
    required this.label,
    required this.getValue,
  });

  /// Display label shown in the preset list (e.g. 'Today', 'This week').
  final String label;

  /// Returns the target [DateTime] when the preset is tapped.
  final DateTime Function() getValue;
}

/// Configuration for a single-date [BTCalendar].
class BTCalendarOptions {
  const BTCalendarOptions({
    this.initialDate,
    this.minDate,
    this.maxDate,
    this.disabledDate,
    this.listDisabled,
    this.listEvent,
    this.presets,
    this.locale = 'id',
    this.showFooter = false,
    this.showPresets = false,
    this.presetsType = BTCalendarPresetsType.scroll,
    this.showAdjacentDays = false,
  });

  /// Date selected when the calendar first renders.
  final DateTime? initialDate;

  /// Earliest selectable date (inclusive).
  final DateTime? minDate;

  /// Latest selectable date (inclusive).
  final DateTime? maxDate;

  /// Return `true` to disable an individual date (predicate-based).
  /// Evaluated in addition to [listDisabled].
  final bool Function(DateTime)? disabledDate;

  /// Specific dates that cannot be selected.
  /// Combined with [disabledDate] — a date is disabled if it appears
  /// in this list OR if [disabledDate] returns `true` for it.
  final List<DateTime>? listDisabled;

  /// Dates that show an event dot below the day number.
  final List<DateTime>? listEvent;

  /// Quick-select presets shown above the grid.
  final List<BTCalendarPreset>? presets;

  /// BCP-47 locale tag. Supports `'id'` (Indonesian) and `'en'` (English).
  final String locale;

  /// Show the Apply / Cancel footer buttons.
  final bool showFooter;

  /// Show the built-in date preset chips
  /// (Yesterday, Today, Tomorrow, This week, Last week, This month, Last month).
  final bool showPresets;

  /// Layout style for the preset chips. Defaults to [BTCalendarPresetsType.scroll].
  final BTCalendarPresetsType presetsType;

  /// When false (default), days from the previous/next month that fill
  /// the grid are hidden — empty and non-interactive.
  /// When true, those days are shown greyed-out.
  final bool showAdjacentDays;

  /// Creates a copy of this [BTCalendarOptions] but with
  /// the given fields replaced with the new values.
  BTCalendarOptions copyWith({
    DateTime? initialDate,
    DateTime? minDate,
    DateTime? maxDate,
    bool Function(DateTime)? disabledDate,
    List<DateTime>? listDisabled,
    List<DateTime>? listEvent,
    List<BTCalendarPreset>? presets,
    String? locale,
    bool? showFooter,
    bool? showPresets,
    BTCalendarPresetsType? presetsType,
    bool? showAdjacentDays,
  }) {
    return BTCalendarOptions(
      initialDate: initialDate ?? this.initialDate,
      minDate: minDate ?? this.minDate,
      maxDate: maxDate ?? this.maxDate,
      disabledDate: disabledDate ?? this.disabledDate,
      listDisabled: listDisabled ?? this.listDisabled,
      listEvent: listEvent ?? this.listEvent,
      presets: presets ?? this.presets,
      locale: locale ?? this.locale,
      showFooter: showFooter ?? this.showFooter,
      showPresets: showPresets ?? this.showPresets,
      presetsType: presetsType ?? this.presetsType,
      showAdjacentDays: showAdjacentDays ?? this.showAdjacentDays,
    );
  }
}

/// Configuration for a date-range [BTCalendar].
class BTRangeCalendarOptions extends BTCalendarOptions {
  const BTRangeCalendarOptions({
    super.initialDate,
    super.minDate,
    super.maxDate,
    super.disabledDate,
    super.listDisabled,
    super.listEvent,
    super.presets,
    super.locale,
    super.showFooter,
    super.showPresets,
    super.presetsType,
    super.showAdjacentDays,
    this.initStartDate,
    this.initFinishDate,
    this.singleMonthView = false,
  });

  /// Pre-selected range start date.
  final DateTime? initStartDate;

  /// Pre-selected range end date.
  final DateTime? initFinishDate;

  /// When true, shows only a single month grid instead of two stacked months.
  /// Set automatically by [BTCalendar.showRange] when type is modal.
  final bool singleMonthView;

  /// Copy with new options.
  BTRangeCalendarOptions copyWith({
    DateTime? initialDate,
    DateTime? minDate,
    DateTime? maxDate,
    bool Function(DateTime)? disabledDate,
    List<DateTime>? listDisabled,
    List<DateTime>? listEvent,
    List<BTCalendarPreset>? presets,
    String? locale,
    bool? showFooter,
    bool? showPresets,
    BTCalendarPresetsType? presetsType,
    bool? showAdjacentDays,
    DateTime? initStartDate,
    DateTime? initFinishDate,
    bool? singleMonthView,
  }) {
    return BTRangeCalendarOptions(
      initialDate: initialDate ?? this.initialDate,
      minDate: minDate ?? this.minDate,
      maxDate: maxDate ?? this.maxDate,
      disabledDate: disabledDate ?? this.disabledDate,
      listDisabled: listDisabled ?? this.listDisabled,
      listEvent: listEvent ?? this.listEvent,
      presets: presets ?? this.presets,
      locale: locale ?? this.locale,
      showFooter: showFooter ?? this.showFooter,
      showPresets: showPresets ?? this.showPresets,
      presetsType: presetsType ?? this.presetsType,
      showAdjacentDays: showAdjacentDays ?? this.showAdjacentDays,
      initStartDate: initStartDate ?? this.initStartDate,
      initFinishDate: initFinishDate ?? this.initFinishDate,
      singleMonthView: singleMonthView ?? this.singleMonthView,
    );
  }
}

/// Configuration for a time-only [BTTimePicker].
class BTTimeCalendarOptions {
  const BTTimeCalendarOptions({
    this.initialTime,
    this.timeVariant = BTCalendarTimeVariant.hhMm,
    this.locale = 'id',
  });

  /// Time displayed when the picker first renders.
  final TimeOfDay? initialTime;

  /// Which columns are shown.
  final BTCalendarTimeVariant timeVariant;

  /// BCP-47 locale tag.
  final String locale;
}

/// Configuration for a combined date-and-time [BTCalendar].
class BTDateTimeCalendarOptions extends BTTimeCalendarOptions {
  const BTDateTimeCalendarOptions({
    super.initialTime,
    super.timeVariant,
    super.locale,
    this.initialDate,
    this.minDate,
    this.maxDate,
    this.disabledDate,
  });

  /// Date selected when the calendar first renders.
  final DateTime? initialDate;

  /// Earliest selectable date (inclusive).
  final DateTime? minDate;

  /// Latest selectable date (inclusive).
  final DateTime? maxDate;

  /// Return `true` to disable an individual date.
  final bool Function(DateTime)? disabledDate;
}

/// BTCalendar — date picker with single-date and date-range modes.
///
/// Use the named constructors for inline embedding:
/// - [BTCalendar.single] — single-date picker
/// - [BTCalendar.range]  — date-range picker
///
/// Use the static `show*()` factories for modal/drawer presentation:
/// - [BTCalendar.show]      — single-date modal or drawer
/// - [BTCalendar.showRange] — date-range modal or drawer
///
/// ## Usage:
/// ```dart
/// // Inline single-date
/// BTCalendar.single(
///   options: BTCalendarOptions(initialDate: DateTime.now()),
///   onDateSelected: (d) => print(d),
/// )
///
/// // Inline range
/// BTCalendar.range(
///   rangeOptions: BTRangeCalendarOptions(),
///   onRangeSelected: (r) => print(r),
/// )
///
/// // Modal — awaitable
/// final date  = await BTCalendar.show(context);
/// final range = await BTCalendar.showRange(context);
/// final time  = await BTTimePicker.show(context, variant: BTCalendarTimeVariant.hhMm);
/// ```
library;

import 'package:btech_tokens/btech_tokens.dart';
import '../button/button.types.dart';
import '../button/button.widget.dart';
import '../drawer/drawer.widget.dart';
import '../drawer/internal/drawer_draggable.dart';
import 'package:btech_ui/src/components/organisms/calendar/calendar.types.dart';
import 'package:btech_ui/src/components/organisms/calendar/internal/calendar.grid.dart';
import 'package:btech_ui/src/components/organisms/calendar/internal/calendar.header.dart';
import 'package:btech_ui/src/components/organisms/calendar/internal/calendar.month_view.dart';
import 'package:btech_ui/src/components/organisms/calendar/internal/calendar.presets.dart';
import 'package:btech_ui/src/components/organisms/calendar/internal/calendar.utils.dart';
import 'package:btech_ui/src/components/organisms/calendar/internal/calendar.year_view.dart';
import 'package:flutter/material.dart';

/// Calendar widget. Use the `show*()` statics for modal presentation.
class BTCalendar extends StatefulWidget {
  const BTCalendar({
    this.options,
    this.rangeOptions,
    this.onDateSelected,
    this.onRangeSelected,
    this.showFooter = true,
    this.onApply,
    this.onCancel,
    this.resetIcon,
    this.isEmbedded = false,
    super.key,
  });

  /// Single-date picker (inline).
  ///
  /// ```dart
  /// BTCalendar.single(
  ///   options: BTCalendarOptions(locale: 'id'),
  ///   onDateSelected: (d) => setState(() => _date = d),
  /// )
  /// ```
  const BTCalendar.single({
    this.options,
    this.onDateSelected,
    this.showFooter = true,
    this.onApply,
    this.onCancel,
    this.resetIcon,
    this.isEmbedded = false,
    super.key,
  })  : rangeOptions = null,
        onRangeSelected = null;

  /// Date-range picker (inline).
  ///
  /// ```dart
  /// BTCalendar.range(
  ///   rangeOptions: BTRangeCalendarOptions(locale: 'id'),
  ///   onRangeSelected: (r) => setState(() => _range = r),
  /// )
  /// ```
  const BTCalendar.range({
    this.rangeOptions,
    this.onRangeSelected,
    this.showFooter = true,
    this.onApply,
    this.onCancel,
    this.resetIcon,
    this.isEmbedded = false,
    super.key,
  })  : options = null,
        onDateSelected = null;

  /// Options for single-date mode.
  final BTCalendarOptions? options;

  /// Options for range mode — when non-null, range selection is enabled.
  final BTRangeCalendarOptions? rangeOptions;

  /// Called when the user taps a date in single-date mode.
  final ValueChanged<DateTime>? onDateSelected;

  /// Called when both range endpoints have been selected.
  final ValueChanged<DateTimeRange>? onRangeSelected;

  /// Show Apply / Cancel footer buttons inside the widget.
  final bool showFooter;

  /// Custom widget shown as the reset/clear button next to the date label.
  /// Defaults to a [Icons.refresh_rounded] icon when null.
  /// Wrap in [GestureDetector] or [InkWell] yourself if you need custom tap handling;
  /// the calendar wraps the default icon in [GestureDetector] automatically.
  final Widget? resetIcon;

  /// When true, the calendar skips its own 16 px outer padding — the host
  /// widget (e.g. [BTDrawer] or [BTDrawerDraggable]) is expected to provide it.
  final bool isEmbedded;

  /// Called when the user taps Apply. Only fires when a date is selected.
  final VoidCallback? onApply;

  /// Called when the user taps Cancel.
  final VoidCallback? onCancel;

  // ── Static show factories ────────────────────────────────────────────────

  /// Show a single-date picker as a centered dialog.
  ///
  /// ```dart
  /// final date = await BTCalendar.show(context);
  /// ```
  static Future<DateTime?> show(
    BuildContext context, {
    BTCalendarOptions? options,
    void Function(DateTime)? onApply,
    VoidCallback? onCancel,
    BTCalendarShowType type = BTCalendarShowType.modal,
    Widget? resetIcon,
    bool showPresets = false,
  }) {
    // ignore: omit_local_variable_types — nullable type required for mutation
    DateTime? picked = options?.initialDate;

    if (type == BTCalendarShowType.drawer) {
      final effectiveOptions = (options ?? const BTCalendarOptions()).copyWith(
          presetsType: BTCalendarPresetsType.scroll,
          showPresets: showPresets,
          showAdjacentDays: true);
      return BTDrawer.show(
        context,
        hasCloseIcon: false,
        hasFooter: false,
        content: AnimatedSize(
          duration: const Duration(milliseconds: 200),
          curve: Curves.easeOut,
          child: BTCalendar(
            options: effectiveOptions,
            resetIcon: resetIcon,
            isEmbedded: true,
            onDateSelected: (d) => picked = d,
            onCancel: () {
              onCancel?.call();
              Navigator.of(context).pop();
            },
            onApply: () {
              if (picked != null) {
                onApply?.call(picked!);
                Navigator.of(context).pop(picked);
              }
            },
          ),
        ),
      );
    }

    final effectiveOptions = (options ?? const BTCalendarOptions()).copyWith(
      presetsType: BTCalendarPresetsType.wrap,
      showPresets: showPresets,
      showAdjacentDays: true,
    );
    return showDialog<DateTime?>(
      context: context,
      barrierColor: Colors.black54,
      builder: (ctx) => _BTCalendarDialogContent(
        bgColor: ctx.btColor.bg.primary,
        child: BTCalendar(
          options: effectiveOptions,
          resetIcon: resetIcon,
          onDateSelected: (d) => picked = d,
          onCancel: () {
            onCancel?.call();
            Navigator.of(ctx).pop();
          },
          onApply: () {
            if (picked != null) {
              onApply?.call(picked!);
              Navigator.of(ctx).pop(picked);
            }
          },
        ),
      ),
    );
  }

  /// Show a date-range picker as a centered dialog.
  ///
  /// ```dart
  /// final range = await BTCalendar.showRange(context);
  /// ```
  static Future<DateTimeRange?> showRange(
    BuildContext context, {
    BTRangeCalendarOptions? options,
    void Function(DateTimeRange)? onApply,
    VoidCallback? onCancel,
    BTCalendarShowType type = BTCalendarShowType.modal,
    Widget? resetIcon,
    bool showPresets = false,
  }) {
    // ignore: omit_local_variable_types — nullable type required for mutation
    DateTimeRange? picked =
        (options?.initStartDate != null && options?.initFinishDate != null)
            ? DateTimeRange(
                start: options!.initStartDate!,
                end: options.initFinishDate!,
              )
            : null;

    if (type == BTCalendarShowType.drawer) {
      const snapSizes = <double>[0.5, 0.65, 0.85, 0.95];
      return BTDrawerDraggable.show<DateTimeRange?>(
        context,
        hasCloseIcon: false,
        hasFooter: false,
        initialSize: 0.9,
        minSize: 0.25,
        maxSize: 0.95,
        snapSizes: snapSizes,
        contentBuilder: (ctx, scrollController, dssCtrl) => _BTRangeScrollable(
          scrollController: scrollController,
          dssCtrl: dssCtrl,
          options: options ?? const BTRangeCalendarOptions(),
          snapSizes: snapSizes,
          minSize: 0.25,
          maxSize: 0.95,
          showPresets: showPresets,
          onApply: (range) {
            onApply?.call(range);
            Navigator.of(context).pop(range);
          },
          onCancel: () {
            onCancel?.call();
            Navigator.of(context).pop();
          },
        ),
      );
    }

    final effectiveOptions =
        (options ?? const BTRangeCalendarOptions()).copyWith(
      presetsType: BTCalendarPresetsType.wrap,
      showPresets: showPresets,
      singleMonthView: true,
      showAdjacentDays: true,
    );
    return showDialog<DateTimeRange>(
      context: context,
      barrierColor: Colors.black54,
      builder: (ctx) => _BTCalendarDialogContent(
        bgColor: ctx.btColor.bg.primary,
        child: BTCalendar(
          rangeOptions: effectiveOptions,
          onRangeSelected: (r) => picked = r,
          onCancel: () {
            onCancel?.call();
            Navigator.of(ctx).pop();
          },
          onApply: () {
            if (picked != null) {
              onApply?.call(picked!);
              Navigator.of(ctx).pop(picked);
            }
          },
        ),
      ),
    );
  }

  @override
  State<BTCalendar> createState() => _BTCalendarState();
}

// ── Inline calendar state ─────────────────────────────────────────────

class _BTCalendarState extends State<BTCalendar> {
  late DateTime _display;
  DateTime? _selectedDate;
  DateTime? _rangeStart;
  DateTime? _rangeEnd;
  BTCalendarDetailState _detailState = BTCalendarDetailState.date;

  bool get _isRange => widget.rangeOptions != null;

  bool get _hasSelection => _isRange
      ? (_rangeStart != null && _rangeEnd != null)
      : _selectedDate != null;

  BTCalendarOptions get _opts =>
      (widget.rangeOptions ?? widget.options) ?? const BTCalendarOptions();

  bool get _canGoPrev {
    if (_detailState == BTCalendarDetailState.year) return false;
    final min = _opts.minDate;
    if (min == null) return true;
    if (_detailState == BTCalendarDetailState.date) {
      // Disable if already showing minDate's month
      return _display.year > min.year ||
          (_display.year == min.year && _display.month > min.month);
    }
    // Month view — disable if already at minDate's year
    return _display.year > min.year;
  }

  bool get _canGoNext {
    if (_detailState == BTCalendarDetailState.year) return false;
    final max = _opts.maxDate;
    if (max == null) return true;
    if (_detailState == BTCalendarDetailState.date) {
      // Disable if already showing maxDate's month
      return _display.year < max.year ||
          (_display.year == max.year && _display.month < max.month);
    }
    // Month view — disable if already at maxDate's year
    return _display.year < max.year;
  }

  @override
  void initState() {
    super.initState();
    _display = _opts.initialDate ?? DateTime.now();
    _selectedDate = _opts.initialDate;
    if (_isRange) {
      _rangeStart = widget.rangeOptions!.initStartDate;
      _rangeEnd = widget.rangeOptions!.initFinishDate;
      if (_rangeStart != null) _display = _rangeStart!;
    }
  }

  void _onPresetTap(DateTime date) {
    setState(() {
      _display = date;
      _detailState = BTCalendarDetailState.date;
      _selectedDate = date;
    });
    widget.onDateSelected?.call(date);
  }

  void _onPresetRangeTap(DateTimeRange range) {
    setState(() {
      _display = range.start;
      _detailState = BTCalendarDetailState.date;
      _rangeStart = range.start;
      _rangeEnd = range.end;
    });
    widget.onRangeSelected?.call(range);
  }

  void _onDateTap(DateTime date) {
    if (!_isRange) {
      setState(() => _selectedDate = date);
      widget.onDateSelected?.call(date);
      return;
    }
    setState(() {
      if (_rangeStart == null) {
        // State 1: no start yet → set start
        _rangeStart = date;
        _rangeEnd = null;
      } else if (_rangeEnd == null) {
        // State 2: start set, waiting for end
        if (isSameDay(date, _rangeStart!)) {
          // Tapped same as start → deselect
          _rangeStart = null;
        } else if (date.isBefore(_rangeStart!)) {
          // Tapped before start → swap
          _rangeEnd = _rangeStart;
          _rangeStart = date;
          widget.onRangeSelected?.call(
            DateTimeRange(start: _rangeStart!, end: _rangeEnd!),
          );
        } else {
          _rangeEnd = date;
          widget.onRangeSelected?.call(
            DateTimeRange(start: _rangeStart!, end: _rangeEnd!),
          );
        }
      } else {
        // State 3: full range set.
        if (isSameDay(date, _rangeStart!)) {
          // Click startDate → keep startDate, clear endDate (re-pick end).
          _rangeEnd = null;
        } else if (isSameDay(date, _rangeEnd!)) {
          // Click endDate (vice versa) → endDate becomes new startDate,
          // clear end so user re-picks from that anchor.
          _rangeStart = _rangeEnd;
          _rangeEnd = null;
        } else if (!date.isBefore(_rangeStart!)) {
          // Tap on/after start → move endDate only (startDate stays).
          _rangeEnd = date;
          widget.onRangeSelected?.call(
            DateTimeRange(start: _rangeStart!, end: _rangeEnd!),
          );
        } else {
          // Tap before start → move startDate only (endDate stays).
          _rangeStart = date;
          widget.onRangeSelected?.call(
            DateTimeRange(start: _rangeStart!, end: _rangeEnd!),
          );
        }
      }
    });
  }

  void _resetSelection() {
    setState(() {
      _selectedDate = null;
      _rangeStart = null;
      _rangeEnd = null;
    });
  }

  // ── Footer helpers ─────────────────────────────────────────────────────────

  String get _selectedDateLabel {
    if (_isRange) {
      final start = _rangeStart;
      final end = _rangeEnd;
      final s = start != null ? formatDate(start, _opts.locale) : 'DD MMM YYYY';
      final e = end != null ? formatDate(end, _opts.locale) : 'DD MMM YYYY';
      return '$s - $e';
    }
    final date = _selectedDate;
    return date != null ? formatDate(date, _opts.locale) : 'DD MMM YYYY';
  }

  Widget _buildFooter(BuildContext context) {
    final c = context.btColor;
    // When embedded in a host that already provides horizontal padding
    // (e.g. BTDrawer), remove footer's own horizontal padding to avoid doubling.
    final hPad = widget.isEmbedded ? 0.0 : 16.0;
    // When embedded, the host has no bottom safe-area padding (BTDrawer sets
    // hasFooter:false), so we add the device's safe-area inset ourselves —
    // equivalent to BTDrawer's hardcoded 48 px (34 safe + 14 extra).
    final bottomPad =
        widget.isEmbedded ? MediaQuery.of(context).padding.bottom + 16.0 : 16.0;

    // Year page — full-width Cancel → goes back to month view
    if (_detailState == BTCalendarDetailState.year) {
      return Padding(
        padding: EdgeInsets.fromLTRB(hPad, 8.0, hPad, bottomPad),
        child: SizedBox(
          width: double.infinity,
          child: BTButton(
            label: calendarCancelLabel(_opts.locale),
            variant: BTButtonVariant.secondaryLight,
            onPressed: () =>
                setState(() => _detailState = BTCalendarDetailState.month),
          ),
        ),
      );
    }

    // Month page — full-width Cancel → goes back to date view
    if (_detailState == BTCalendarDetailState.month) {
      return Padding(
        padding: EdgeInsets.fromLTRB(hPad, 8.0, hPad, bottomPad),
        child: SizedBox(
          width: double.infinity,
          child: BTButton(
            label: calendarCancelLabel(_opts.locale),
            variant: BTButtonVariant.secondaryLight,
            onPressed: () =>
                setState(() => _detailState = BTCalendarDetailState.date),
          ),
        ),
      );
    }

    // Date page — date label (with reset) + Cancel | Terapkan (horizontal)
    return Padding(
      padding: EdgeInsets.fromLTRB(hPad, 16.0, hPad, bottomPad),
      child: Column(
        mainAxisSize: MainAxisSize.min,
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          Center(
            child: Row(
              mainAxisSize: MainAxisSize.min,
              children: [
                Text(
                  _selectedDateLabel,
                  style: TextStyle(
                    fontFamily: BTTypography.fontFamily,
                    fontSize: 14.0,
                    fontWeight: FontWeight.w700,
                    color: c.brand.primary,
                  ),
                ),
                if (_hasSelection) ...[
                  SizedBox(width: 8.0),
                  if (widget.resetIcon != null)
                    GestureDetector(
                      onTap: _resetSelection,
                      child: widget.resetIcon!,
                    )
                  else
                    GestureDetector(
                      onTap: _resetSelection,
                      child: Icon(
                        Icons.refresh_rounded,
                        size: 20,
                        color: c.brand.primary,
                      ),
                    ),
                ],
              ],
            ),
          ),
          SizedBox(height: 16.0),
          Row(
            children: [
              Expanded(
                child: BTButton(
                  label: calendarCancelLabel(_opts.locale),
                  variant: BTButtonVariant.secondaryLight,
                  onPressed: widget.onCancel,
                ),
              ),
              SizedBox(width: 8.0),
              Expanded(
                child: BTButton(
                  label: calendarApplyLabel(_opts.locale),
                  onPressed: _hasSelection ? widget.onApply : null,
                ),
              ),
            ],
          ),
        ],
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    return Column(
      mainAxisSize: MainAxisSize.min,
      children: [
        // Header + grid — 16px padding on all sides except bottom.
        // Omitted when isEmbedded=true (host widget provides the padding).
        Padding(
          padding: widget.isEmbedded
              ? EdgeInsets.zero
              : EdgeInsets.fromLTRB(16.0, 16.0, 16.0, 16.0),
          child: Column(
            mainAxisSize: MainAxisSize.min,
            children: [
              BTCalendarHeader(
                displayDate: _display,
                detailState: _detailState,
                locale: _opts.locale,
                canGoPrev: _canGoPrev,
                canGoNext: _canGoNext,
                onPrev: _detailState == BTCalendarDetailState.year
                    ? null
                    : () => setState(
                          () => _display = addMonths(
                            _display,
                            _detailState == BTCalendarDetailState.month
                                ? -12
                                : -1,
                          ),
                        ),
                onNext: _detailState == BTCalendarDetailState.year
                    ? null
                    : () => setState(
                          () => _display = addMonths(
                            _display,
                            _detailState == BTCalendarDetailState.month
                                ? 12
                                : 1,
                          ),
                        ),
                onDetailStateChanged: (s) => setState(() => _detailState = s),
              ),
              SizedBox(height: 8.0),
              switch (_detailState) {
                BTCalendarDetailState.date when _isRange =>
                  (widget.rangeOptions?.singleMonthView ?? false)
                      ? BTCalendarGrid(
                          displayDate: _display,
                          locale: _opts.locale,
                          rangeStart: _rangeStart,
                          rangeEnd: _rangeEnd,
                          minDate: _opts.minDate,
                          maxDate: _opts.maxDate,
                          disabledDate: _opts.disabledDate,
                          listDisabled: _opts.listDisabled,
                          listEvent: _opts.listEvent,
                          onDateTap: _onDateTap,
                          showAdjacentDays: _opts.showAdjacentDays,
                        )
                      : Column(
                          mainAxisSize: MainAxisSize.min,
                          children: [
                            BTCalendarGrid(
                              displayDate: _display,
                              locale: _opts.locale,
                              monthTitle: getMonthName(_display, _opts.locale),
                              rangeStart: _rangeStart,
                              rangeEnd: _rangeEnd,
                              minDate: _opts.minDate,
                              maxDate: _opts.maxDate,
                              disabledDate: _opts.disabledDate,
                              listDisabled: _opts.listDisabled,
                              listEvent: _opts.listEvent,
                              onDateTap: _onDateTap,
                              showAdjacentDays: _opts.showAdjacentDays,
                            ),
                            SizedBox(height: 8.0),
                            BTCalendarGrid(
                              displayDate: addMonths(_display, 1),
                              locale: _opts.locale,
                              monthTitle: getMonthName(
                                addMonths(_display, 1),
                                _opts.locale,
                              ),
                              rangeStart: _rangeStart,
                              rangeEnd: _rangeEnd,
                              minDate: _opts.minDate,
                              maxDate: _opts.maxDate,
                              disabledDate: _opts.disabledDate,
                              listDisabled: _opts.listDisabled,
                              listEvent: _opts.listEvent,
                              onDateTap: _onDateTap,
                              showAdjacentDays: _opts.showAdjacentDays,
                            ),
                          ],
                        ),
                BTCalendarDetailState.date => BTCalendarGrid(
                    displayDate: _display,
                    locale: _opts.locale,
                    selectedDate: _selectedDate,
                    minDate: _opts.minDate,
                    maxDate: _opts.maxDate,
                    disabledDate: _opts.disabledDate,
                    listDisabled: _opts.listDisabled,
                    listEvent: _opts.listEvent,
                    onDateTap: _onDateTap,
                    showAdjacentDays: _opts.showAdjacentDays,
                  ),
                BTCalendarDetailState.month => BTCalendarMonthView(
                    displayDate: _display,
                    locale: _opts.locale,
                    minDate: _opts.minDate,
                    maxDate: _opts.maxDate,
                    onMonthSelected: (m) => setState(() {
                      _display = DateTime(_display.year, m);
                      _detailState = BTCalendarDetailState.date;
                      // Committing to a new month clears any prior selection so
                      // the user picks a fresh date in the newly-navigated month.
                      _selectedDate = null;
                      _rangeStart = null;
                      _rangeEnd = null;
                    }),
                  ),
                BTCalendarDetailState.year => Padding(
                    padding: EdgeInsets.only(bottom: 16.0),
                    child: BTCalendarYearView(
                      displayDate: _display,
                      minDate: _opts.minDate,
                      maxDate: _opts.maxDate,
                      onYearSelected: (y) => setState(() {
                        _display = DateTime(y, _display.month);
                        _detailState = BTCalendarDetailState.month;
                        // Committing to a new year clears any prior selection.
                        _selectedDate = null;
                        _rangeStart = null;
                        _rangeEnd = null;
                      }),
                    ),
                  ),
              },
            ],
          ),
        ),
        // Presets — only on the date page, horizontally scrollable
        if (_opts.showPresets &&
            _detailState == BTCalendarDetailState.date) ...[
          if (_opts.presetsType == BTCalendarPresetsType.scroll)
            SizedBox(height: 8.0),
          BTCalendarPresets(
            locale: _opts.locale,
            type: _opts.presetsType,
            minDate: _opts.minDate,
            maxDate: _opts.maxDate,
            listDisabled: _opts.listDisabled,
            onDateSelected: _isRange ? null : _onPresetTap,
            onRangeSelected: _isRange ? _onPresetRangeTap : null,
          ),
        ],
        // Footer — state-aware (date: date label + Apply/Cancel;
        //                        month/year: Cancel-only back nav)
        if (widget.showFooter)
          _buildFooter(context)
        else
          SizedBox(height: 16.0),
      ],
    );
  }
}

