// ── Range scrollable body (drawer variant) ────────────────────────────────────

/// Full-height Column used as the [BTDrawerDraggable] contentBuilder for
/// range selection. Shows all months between [options.minDate] and
/// [options.maxDate] in a scrollable list, with a pinned footer below.
class _BTRangeScrollable extends StatefulWidget {
  const _BTRangeScrollable({
    required this.scrollController,
    required this.dssCtrl,
    required this.options,
    required this.onApply,
    required this.onCancel,
    this.snapSizes = const [0.6, 0.75, 0.85],
    this.minSize = 0.25,
    this.maxSize = 0.95,
    this.showPresets = false,
  });

  final ScrollController scrollController;
  final DraggableScrollableController dssCtrl;
  final BTRangeCalendarOptions options;
  final ValueChanged<DateTimeRange> onApply;
  final VoidCallback onCancel;
  final List<double> snapSizes;
  final double minSize;
  final double maxSize;
  final bool showPresets;

  @override
  State<_BTRangeScrollable> createState() => _BTRangeScrollableState();
}

class _BTRangeScrollableState extends State<_BTRangeScrollable> {
  // ListView top padding — must match the ListView's own padding.top.
  static const double _listTopPad = 8.0;

  // Per-item height, measured from the first rendered item in postFrameCallback.
  // Falls back to 280 (= title 20 + titlePad 4 + weekday 20 + gap 4 + 6×36 + itemPad 16).
  double _itemHeight = 280.0;

  // GlobalKey on item 0 so we can measure it once after the first frame.
  final GlobalKey _firstItemKey = GlobalKey();

  late List<DateTime> _months;
  DateTime? _rangeStart;
  DateTime? _rangeEnd;
  int _currentVisibleMonthIdx = 0;

  // Drill-down navigation state (date → month → year).
  BTCalendarDetailState _detailState = BTCalendarDetailState.date;
  // The date driving the month/year picker views; kept in sync with the
  // currently-visible month while in date mode.
  late DateTime _headerDisplay;

  @override
  void initState() {
    super.initState();
    final opts = widget.options;
    final startYear = opts.minDate?.year ?? DateTime.now().year - 1;
    final endYear = opts.maxDate?.year ?? DateTime.now().year + 2;
    _months = [
      for (var y = startYear; y <= endYear; y++)
        for (var m = 1; m <= 12; m++) DateTime(y, m),
    ];
    _rangeStart = opts.initStartDate;
    _rangeEnd = opts.initFinishDate;
    _headerDisplay = _months.first;

    widget.scrollController.addListener(_updateVisibleMonth);

    WidgetsBinding.instance.addPostFrameCallback((_) {
      // Measure the actual height of item 0 (always visible on first frame).
      final box =
          _firstItemKey.currentContext?.findRenderObject() as RenderBox?;
      if (box != null) _itemHeight = box.size.height;

      // Jump to the initial pivot month.
      final pivot = opts.initStartDate ?? DateTime.now();
      final idx = _months.indexWhere(
        (m) => m.year == pivot.year && m.month == pivot.month,
      );
      if (idx > 0 && widget.scrollController.hasClients) {
        widget.scrollController.jumpTo(_listTopPad + idx * _itemHeight);
        setState(() {
          _currentVisibleMonthIdx = idx;
          _headerDisplay = _months[idx];
        });
      }
    });
  }

  @override
  void dispose() {
    widget.scrollController.removeListener(_updateVisibleMonth);
    super.dispose();
  }

  void _resizeFor(BTCalendarDetailState state) {
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (!mounted || !widget.dssCtrl.isAttached) return;
      final mq = MediaQuery.of(context);
      final screenH = mq.size.height;
      final double fraction;
      switch (state) {
        case BTCalendarDetailState.date:
          fraction = 0.85;
        case BTCalendarDetailState.month:
          // Compute exact pixel height so the 3×4 month grid fits with no
          // blank space. The grid uses childAspectRatio=2.5, crossAxisCount=3,
          // mainAxisSpacing=8, crossAxisSpacing=8.
          final contentW = mq.size.width - 32; // 16px h-pad each side
          final cellW = (contentW - 16) / 3; // 2 × 8px crossAxisSpacing
          final gridH = 4 * (cellW / 2.5) + 3 * 8; // 4 rows + 3 row-gaps
          // Fixed non-grid heights (measured from actual widget stack):
          //  drag handle 20 + drawer header (24+25+16=65) +
          //  cal header (8+34+4=46) + sv-padding (8+8=16) + footer (12+40+16=68)
          final totalH = 165 + gridH;
          fraction = (totalH / screenH).clamp(widget.minSize, widget.maxSize);
        case BTCalendarDetailState.year:
          fraction = 0.75.clamp(widget.minSize, widget.maxSize);
      }
      widget.dssCtrl.animateTo(
        fraction,
        duration: const Duration(milliseconds: 200),
        curve: Curves.easeOut,
      );
    });
  }

  void _updateVisibleMonth() {
    if (!widget.scrollController.hasClients) return;
    if (_detailState != BTCalendarDetailState.date) return;
    final idx = ((widget.scrollController.offset - _listTopPad) / _itemHeight)
        .floor()
        .clamp(0, _months.length - 1);
    if (idx != _currentVisibleMonthIdx) {
      setState(() {
        _currentVisibleMonthIdx = idx;
        _headerDisplay = _months[idx];
      });
    }
  }

  void _scrollToMonth(int idx) {
    widget.scrollController.animateTo(
      _listTopPad + idx * _itemHeight,
      duration: const Duration(milliseconds: 300),
      curve: Curves.easeOut,
    );
  }

  void _onDateTap(DateTime date) {
    setState(() {
      if (_rangeStart == null) {
        // State 1: no start yet → set start.
        _rangeStart = date;
        _rangeEnd = null;
      } else if (_rangeEnd == null) {
        // State 2: start set, waiting for end.
        if (isSameDay(date, _rangeStart!)) {
          // Click same start → unselect (State 1).
          _rangeStart = null;
        } else if (date.isBefore(_rangeStart!)) {
          _rangeEnd = _rangeStart;
          _rangeStart = date;
        } else {
          _rangeEnd = date;
        }
      } else {
        // State 3: full range set.
        if (isSameDay(date, _rangeStart!)) {
          // Click startDate → keep startDate, clear endDate (re-pick end).
          _rangeEnd = null;
        } else if (isSameDay(date, _rangeEnd!)) {
          // Click endDate (vice versa) → endDate becomes new startDate,
          // clear end so user re-picks from that anchor.
          _rangeStart = _rangeEnd;
          _rangeEnd = null;
        } else if (!date.isBefore(_rangeStart!)) {
          // Tap on/after start → move endDate only (startDate stays).
          _rangeEnd = date;
        } else {
          // Tap before start → move startDate only (endDate stays).
          _rangeStart = date;
        }
      }
    });
  }

  void _onPresetSelected(DateTimeRange range) {
    setState(() {
      _rangeStart = range.start;
      _rangeEnd = range.end;
    });
    final idx = _months.indexWhere(
      (m) => m.year == range.start.year && m.month == range.start.month,
    );
    if (idx >= 0 && widget.scrollController.hasClients) {
      widget.scrollController.animateTo(
        _listTopPad + idx * _itemHeight,
        duration: const Duration(milliseconds: 300),
        curve: Curves.easeOut,
      );
    }
  }

  void _clearSelection() => setState(() {
        _rangeStart = null;
        _rangeEnd = null;
      });

  String _fmt(DateTime d) {
    final month = getMonthName(d, widget.options.locale).substring(0, 3);
    return '${d.day.toString().padLeft(2, '0')} $month ${d.year}';
  }

  @override
  Widget build(BuildContext context) {
    final colors = context.btColor;
    final opts = widget.options;
    final hasSelection = _rangeStart != null && _rangeEnd != null;

    // ── Nav button logic (depends on detailState) ───────────────────────────
    final bool canGoPrev;
    final bool canGoNext;
    final VoidCallback? onPrev;
    final VoidCallback? onNext;
    switch (_detailState) {
      case BTCalendarDetailState.date:
        canGoPrev = _currentVisibleMonthIdx > 0;
        canGoNext = _currentVisibleMonthIdx < _months.length - 1;
        onPrev = canGoPrev
            ? () => _scrollToMonth(_currentVisibleMonthIdx - 1)
            : null;
        onNext = canGoNext
            ? () => _scrollToMonth(_currentVisibleMonthIdx + 1)
            : null;
      case BTCalendarDetailState.month:
        final prevYear = _headerDisplay.year - 1;
        final nextYear = _headerDisplay.year + 1;
        canGoPrev = opts.minDate == null || prevYear >= opts.minDate!.year;
        canGoNext = opts.maxDate == null || nextYear <= opts.maxDate!.year;
        onPrev = canGoPrev
            ? () {
                final before = prevYear < _months.first.year
                    ? [
                        for (var m = 1; m <= 12; m++) DateTime(prevYear, m),
                      ]
                    : const <DateTime>[];
                setState(() {
                  if (before.isNotEmpty) {
                    _months = [...before, ..._months];
                    _currentVisibleMonthIdx += before.length;
                  }
                  _headerDisplay = DateTime(prevYear, _headerDisplay.month);
                });
              }
            : null;
        onNext = canGoNext
            ? () {
                final after = nextYear > _months.last.year
                    ? [
                        for (var m = 1; m <= 12; m++) DateTime(nextYear, m),
                      ]
                    : const <DateTime>[];
                setState(() {
                  if (after.isNotEmpty) {
                    _months = [..._months, ...after];
                  }
                  _headerDisplay = DateTime(nextYear, _headerDisplay.month);
                });
              }
            : null;
      case BTCalendarDetailState.year:
        canGoPrev = false;
        canGoNext = false;
        onPrev = null;
        onNext = null;
    }

    // ── Middle content: date list | month grid | year grid ──────────────────
    final Widget middleContent;
    switch (_detailState) {
      case BTCalendarDetailState.date:
        middleContent = Flexible(
          child: ListView.builder(
            controller: widget.scrollController,
            physics: const AlwaysScrollableScrollPhysics(),
            padding: EdgeInsets.fromLTRB(16.0, 8.0, 16.0, 8.0),
            itemCount: _months.length,
            itemBuilder: (ctx, i) => Padding(
              key: i == 0 ? _firstItemKey : null,
              padding: EdgeInsets.only(bottom: 16.0),
              child: BTCalendarGrid(
                displayDate: _months[i],
                locale: opts.locale,
                monthTitle: getMonthName(_months[i], opts.locale),
                rangeStart: _rangeStart,
                rangeEnd: _rangeEnd,
                minDate: opts.minDate,
                maxDate: opts.maxDate,
                disabledDate: opts.disabledDate,
                listDisabled: opts.listDisabled,
                listEvent: opts.listEvent,
                onDateTap: _onDateTap,
              ),
            ),
          ),
        );
      case BTCalendarDetailState.month:
        middleContent = Expanded(
          child: SingleChildScrollView(
            controller:
                widget.scrollController, // keeps dssCtrl.isAttached=true
            padding: EdgeInsets.fromLTRB(16.0, 8.0, 16.0, 8.0),
            child: BTCalendarMonthView(
              displayDate: _headerDisplay,
              locale: opts.locale,
              minDate: opts.minDate,
              maxDate: opts.maxDate,
              onMonthSelected: (month) {
                final target = DateTime(_headerDisplay.year, month);
                final idx = _months.indexWhere(
                  (m) => m.year == target.year && m.month == target.month,
                );
                setState(() {
                  _headerDisplay = target;
                  _detailState = BTCalendarDetailState.date;
                  if (idx >= 0) _currentVisibleMonthIdx = idx;
                });
                _resizeFor(BTCalendarDetailState.date);
                // postFrameCallback — ListView re-enters tree on this setState;
                // jumpTo must wait until it is rendered (avoids "not attached" error)
                if (idx >= 0) {
                  WidgetsBinding.instance.addPostFrameCallback((_) {
                    if (widget.scrollController.hasClients) {
                      widget.scrollController
                          .jumpTo(_listTopPad + idx * _itemHeight);
                    }
                  });
                }
              },
            ),
          ),
        );
      case BTCalendarDetailState.year:
        middleContent = Expanded(
          child: Padding(
            padding: EdgeInsets.fromLTRB(16.0, 8.0, 16.0, 16.0),
            child: BTCalendarYearView(
              displayDate: _headerDisplay,
              minDate: opts.minDate,
              maxDate: opts.maxDate,
              height: null, // Expanded controls the height
              scrollController:
                  widget.scrollController, // keeps dssCtrl.isAttached=true
              onYearSelected: (year) {
                // Extend _months when the picked year falls outside the
                // current list so the date page can jump to the right position.
                final before = year < _months.first.year
                    ? [
                        for (var y = year; y < _months.first.year; y++)
                          for (var m = 1; m <= 12; m++) DateTime(y, m),
                      ]
                    : const <DateTime>[];
                final after = year > _months.last.year
                    ? [
                        for (var y = _months.last.year + 1; y <= year; y++)
                          for (var m = 1; m <= 12; m++) DateTime(y, m),
                      ]
                    : const <DateTime>[];
                setState(() {
                  if (before.isNotEmpty) {
                    _months = [...before, ..._months];
                    _currentVisibleMonthIdx += before.length;
                  }
                  if (after.isNotEmpty) {
                    _months = [..._months, ...after];
                  }
                  _headerDisplay = DateTime(year, _headerDisplay.month);
                  _detailState = BTCalendarDetailState.month;
                });
                _resizeFor(BTCalendarDetailState.month);
              },
            ),
          ),
        );
    }

    return Column(
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: [
        // ── Pinned header — drill-down: date → month → year ──────────────────
        GestureDetector(
          behavior: HitTestBehavior.translucent,
          onVerticalDragUpdate: (details) {
            if (!widget.dssCtrl.isAttached) return;
            final screenH = MediaQuery.of(context).size.height;
            final newSize = (widget.dssCtrl.size - details.delta.dy / screenH)
                .clamp(widget.minSize, widget.maxSize);
            widget.dssCtrl.jumpTo(newSize);
          },
          onVerticalDragEnd: (_) {
            if (!widget.dssCtrl.isAttached) return;
            final cur = widget.dssCtrl.size;
            final snaps = <double>[
              widget.minSize,
              ...widget.snapSizes,
              widget.maxSize,
            ];
            final nearest = snaps.reduce(
              (a, b) => (a - cur).abs() < (b - cur).abs() ? a : b,
            );
            widget.dssCtrl.animateTo(
              nearest,
              duration: const Duration(milliseconds: 200),
              curve: Curves.easeOut,
            );
          },
          child: Padding(
            padding: EdgeInsets.fromLTRB(16.0, 8.0, 16.0, 4.0),
            child: BTCalendarHeader(
              displayDate: _headerDisplay,
              detailState: _detailState,
              locale: opts.locale,
              canGoPrev: canGoPrev,
              canGoNext: canGoNext,
              onPrev: onPrev,
              onNext: onNext,
              onDetailStateChanged: (s) {
                setState(() => _detailState = s);
                _resizeFor(s);
              },
            ),
          ),
        ),

        // ── Dynamic middle content ────────────────────────────────────────────
        middleContent,

        // ── Pinned footer ─────────────────────────────────────────────────────
        // Date mode: presets + date label + Cancel | Apply (horizontal).
        // Month/Year mode: single Cancel button that goes back one level.
        Builder(
          builder: (ctx) {
            final bottomPad = MediaQuery.of(ctx).padding.bottom + 16.0;
            return Container(
              color: colors.bg.primary,
              padding: EdgeInsets.fromLTRB(16.0, 12.0, 16.0, bottomPad),
              child: _detailState == BTCalendarDetailState.date
                  ? Column(
                      mainAxisSize: MainAxisSize.min,
                      crossAxisAlignment: CrossAxisAlignment.stretch,
                      children: [
                        // Preset chips — horizontally scrollable
                        if (widget.showPresets) ...[
                          BTCalendarPresets(
                            locale: opts.locale,
                            type: BTCalendarPresetsType.scroll,
                            onRangeSelected: _onPresetSelected,
                            minDate: opts.minDate,
                            maxDate: opts.maxDate,
                            listDisabled: opts.listDisabled,
                          ),
                          SizedBox(height: 8.0),
                        ],
                        // Date range label — always visible; placeholder when no selection
                        Center(
                          child: Row(
                            mainAxisSize: MainAxisSize.min,
                            children: [
                              Text(
                                hasSelection
                                    ? '${_fmt(_rangeStart!)}  –  ${_fmt(_rangeEnd!)}'
                                    : 'DD MMM YYYY  –  DD MMM YYYY',
                                style: TextStyle(
                                  fontFamily: BTTypography.fontFamily,
                                  fontSize: 14.0,
                                  fontWeight: FontWeight.w700,
                                  color: hasSelection
                                      ? colors.brand.primary
                                      : colors.text.tertiary,
                                ),
                              ),
                              if (hasSelection) ...[
                                SizedBox(width: 8.0),
                                GestureDetector(
                                  onTap: _clearSelection,
                                  child: Icon(
                                    Icons.refresh_rounded,
                                    size: 20,
                                    color: colors.brand.primary,
                                  ),
                                ),
                              ],
                            ],
                          ),
                        ),
                        SizedBox(height: 16.0),
                        Row(
                          children: [
                            Expanded(
                              child: BTButton(
                                label: calendarCancelLabel(opts.locale),
                                variant: BTButtonVariant.secondaryLight,
                                onPressed: widget.onCancel,
                              ),
                            ),
                            SizedBox(width: 8.0),
                            Expanded(
                              child: BTButton(
                                label: calendarApplyLabel(opts.locale),
                                onPressed: hasSelection
                                    ? () => widget.onApply(
                                          DateTimeRange(
                                            start: _rangeStart!,
                                            end: _rangeEnd!,
                                          ),
                                        )
                                    : null,
                              ),
                            ),
                          ],
                        ),
                      ],
                    )
                  : BTButton(
                      // Month/Year pages: Cancel goes back one level, no Apply shown
                      label: calendarCancelLabel(opts.locale),
                      variant: BTButtonVariant.secondaryLight,
                      onPressed: () {
                        final prev = _detailState == BTCalendarDetailState.year
                            ? BTCalendarDetailState.month
                            : BTCalendarDetailState.date;
                        setState(() => _detailState = prev);
                        _resizeFor(prev);
                      },
                    ),
            );
          },
        ),
      ],
    );
  }
}

import 'package:btech_tokens/btech_tokens.dart';
import 'package:btech_ui/src/components/organisms/calendar/internal/calendar.utils.dart';
import 'package:flutter/material.dart';

/// 7-column weekday header + 6×7 day-cell grid.
///
/// All visual state (selected, rangeStart, rangeEnd, inRange, today,
/// disabled, outside-month, event) is resolved per-cell on each build.
/// Press state is instant (CLAUDE.md §12 — no AnimatedContainer).
///
/// Performance: BTCalendarGrid is StatefulWidget tracking a single
/// _pressedDate so the 42 cells can be StatelessWidgets — eliminates
/// 42 State objects per month, which was the root cause of scroll lag.
class BTCalendarGrid extends StatefulWidget {
  const BTCalendarGrid({
    required this.displayDate,
    required this.locale,
    this.monthTitle,
    this.selectedDate,
    this.rangeStart,
    this.rangeEnd,
    this.minDate,
    this.maxDate,
    this.disabledDate,
    this.listDisabled,
    this.listEvent,
    this.onDateTap,
    this.showAdjacentDays = false,
    super.key,
  });

  final DateTime displayDate;
  final String locale;

  /// Optional month title rendered above the weekday header (e.g. "Mei 2025").
  /// Used in range-calendar two-month inline layout.
  final String? monthTitle;
  final DateTime? selectedDate;
  final DateTime? rangeStart;
  final DateTime? rangeEnd;
  final DateTime? minDate;
  final DateTime? maxDate;
  final bool Function(DateTime)? disabledDate;
  final List<DateTime>? listDisabled;
  final List<DateTime>? listEvent;
  final ValueChanged<DateTime>? onDateTap;

  /// When false (default), days from the previous/next month that fill the
  /// 6×7 grid are hidden — cells are empty and non-interactive.
  /// When true, those days are shown greyed-out (the standard behaviour).
  final bool showAdjacentDays;

  @override
  State<BTCalendarGrid> createState() => _BTCalendarGridState();
}

class _BTCalendarGridState extends State<BTCalendarGrid> {
  // Single press-tracking for all 42 cells — avoids 42 individual State objects.
  DateTime? _pressedDate;

  bool _isDisabled(DateTime d) {
    if (widget.minDate != null &&
        d.isBefore(DateTime(
          widget.minDate!.year,
          widget.minDate!.month,
          widget.minDate!.day,
        ))) {
      return true;
    }
    if (widget.maxDate != null &&
        d.isAfter(DateTime(
          widget.maxDate!.year,
          widget.maxDate!.month,
          widget.maxDate!.day,
        ))) {
      return true;
    }
    if (widget.listDisabled?.any((disabled) => isSameDay(disabled, d)) ??
        false) {
      return true;
    }
    return widget.disabledDate?.call(d) ?? false;
  }

  bool _hasEvent(DateTime d) =>
      widget.listEvent?.any((e) => isSameDay(e, d)) ?? false;

  void _onPressChanged(DateTime date, bool pressed) {
    setState(() => _pressedDate = pressed ? date : null);
  }

  @override
  Widget build(BuildContext context) {
    final days = generateCalendarDays(
      widget.displayDate.year,
      widget.displayDate.month,
    );
    final weekdays = getWeekdayNames(widget.locale);

    return Column(
      children: [
        // Optional month title (used in range two-month inline layout)
        if (widget.monthTitle != null)
          Padding(
            padding: EdgeInsets.only(bottom: 4.0),
            child: Center(
              child: Text(
                widget.monthTitle!,
                style: TextStyle(
                  fontFamily: BTTypography.fontFamily,
                  fontSize: 14.0,
                  fontWeight: FontWeight.w500,
                  color: context.btColor.text.secondary,
                ),
              ),
            ),
          ),
        // Weekday header row — explicit height for predictable layout math
        SizedBox(
          height: 20.0,
          child: Row(
            children: weekdays
                .map(
                  (w) => Expanded(
                    child: Center(
                      child: Text(
                        w,
                        style: TextStyle(
                          fontFamily: BTTypography.fontFamily,
                          fontSize: 12.0,
                          fontWeight: FontWeight.w500,
                          color: context.btColor.text.secondary,
                        ),
                      ),
                    ),
                  ),
                )
                .toList(),
          ),
        ),
        SizedBox(height: 4.0),
        // 6 rows × 7 columns
        for (var row = 0; row < 6; row++)
          Row(
            children: [
              for (var col = 0; col < 7; col++)
                Expanded(
                  child: _BTDayCell(
                    date: days[row * 7 + col],
                    displayMonth: widget.displayDate.month,
                    selectedDate: widget.selectedDate,
                    rangeStart: widget.rangeStart,
                    rangeEnd: widget.rangeEnd,
                    isDisabled: _isDisabled(days[row * 7 + col]),
                    hasEvent: _hasEvent(days[row * 7 + col]),
                    isPressed: _pressedDate != null &&
                        isSameDay(_pressedDate!, days[row * 7 + col]),
                    onTap: widget.onDateTap,
                    onPressChanged: _onPressChanged,
                    showAdjacentDays: widget.showAdjacentDays,
                  ),
                ),
            ],
          ),
      ],
    );
  }
}

// ── Day cell ─────────────────────────────────────────────────────────────────

// StatelessWidget — no per-cell State objects, dramatically reduces scroll jank.
// Press state is owned by BTCalendarGrid (1 State instead of 42).
class _BTDayCell extends StatelessWidget {
  const _BTDayCell({
    required this.date,
    required this.displayMonth,
    required this.isDisabled,
    required this.hasEvent,
    required this.isPressed,
    required this.onPressChanged,
    required this.showAdjacentDays,
    this.selectedDate,
    this.rangeStart,
    this.rangeEnd,
    this.onTap,
  });

  final DateTime date;
  final int displayMonth;
  final DateTime? selectedDate;
  final DateTime? rangeStart;
  final DateTime? rangeEnd;
  final bool isDisabled;
  final bool hasEvent;
  final bool isPressed;
  final bool showAdjacentDays;
  final void Function(DateTime date, bool pressed) onPressChanged;
  final ValueChanged<DateTime>? onTap;

  static const double _cellSize = 36;
  static const _radius = Radius.circular(8);

  bool get _isOutside => date.month != displayMonth;
  bool get _isSelected =>
      selectedDate != null && isSameDay(selectedDate!, date);
  bool get _isRangeStart =>
      rangeStart != null && isSameDay(rangeStart!, date);
  bool get _isRangeEnd => rangeEnd != null && isSameDay(rangeEnd!, date);
  bool get _isInRange {
    if (rangeStart == null || rangeEnd == null) return false;
    if (_isRangeStart || _isRangeEnd) return false;
    return isInRange(date, rangeStart!, rangeEnd!);
  }

  bool get _isToday => isToday(date);
  bool get _isEndpoint => _isSelected || _isRangeStart || _isRangeEnd;

  Color _resolveFg(BTColorTheme c) {
    // Endpoint (selected/rangeStart/rangeEnd) always shows white — even outside month.
    if (_isEndpoint) return c.text.inverse;
    if (_isOutside) return c.text.tertiary;
    if (isDisabled) return c.text.disabled;
    return c.text.primary;
  }

  @override
  Widget build(BuildContext context) {
    // Hidden adjacent day — empty non-interactive placeholder to preserve grid layout.
    if (_isOutside && !showAdjacentDays) {
      return const SizedBox(height: _cellSize);
    }

    final c = context.btColor;
    final fg = _resolveFg(c);

    final bool isVisualEndpoint = _isEndpoint;

    // Day number + optional event dot
    final dayContent = Column(
      mainAxisSize: MainAxisSize.min,
      mainAxisAlignment: MainAxisAlignment.center,
      children: [
        Text(
          '${date.day}',
          style: TextStyle(
            fontFamily: BTTypography.fontFamily,
            fontSize: 13.0,
            fontWeight: isVisualEndpoint ? FontWeight.w700 : FontWeight.w400,
            color: fg,
          ),
        ),
        if (hasEvent)
          Container(
            width: 4.0,
            height: 4.0,
            margin: EdgeInsets.only(top: 2.0),
            decoration: BoxDecoration(
              shape: BoxShape.circle,
              color: c.brand.secondary,
            ),
          ),
      ],
    );

    // Centered 36×36 selection indicator — never stretches horizontally
    Widget indicator(
      Color bg, {
      BoxBorder? border,
      BorderRadius radius = const BorderRadius.all(_radius),
    }) =>
        Container(
          width: _cellSize,
          height: _cellSize,
          decoration: BoxDecoration(
            color: bg,
            borderRadius: radius,
            border: border,
          ),
          child: Center(child: dayContent),
        );

    Widget cellVisual;

    if (_isInRange) {
      // Full-width fill for in-range dates — shows continuity across month boundaries.
      cellVisual = Container(
        height: _cellSize,
        color: c.brand.primarySubtle,
        child: Center(child: dayContent),
      );
    } else if (_isRangeStart && rangeEnd != null) {
      // Left-rounded indicator; right-half fill extends toward next range cells
      cellVisual = SizedBox(
        height: _cellSize,
        child: Stack(
          children: [
            Positioned.fill(
              child: Align(
                alignment: Alignment.centerRight,
                child: FractionallySizedBox(
                  widthFactor: 0.5,
                  child: Container(color: c.brand.primarySubtle),
                ),
              ),
            ),
            Center(
              child: indicator(
                c.brand.primaryBold,
                radius: const BorderRadius.only(
                  topLeft: _radius,
                  bottomLeft: _radius,
                ),
              ),
            ),
          ],
        ),
      );
    } else if (_isRangeEnd) {
      // Right-rounded indicator; left-half fill extends from previous range cells
      cellVisual = SizedBox(
        height: _cellSize,
        child: Stack(
          children: [
            Positioned.fill(
              child: Align(
                alignment: Alignment.centerLeft,
                child: FractionallySizedBox(
                  widthFactor: 0.5,
                  child: Container(color: c.brand.primarySubtle),
                ),
              ),
            ),
            Center(
              child: indicator(
                c.brand.primaryBold,
                radius: const BorderRadius.only(
                  topRight: _radius,
                  bottomRight: _radius,
                ),
              ),
            ),
          ],
        ),
      );
    } else if (isVisualEndpoint) {
      // Plain selected or range start awaiting end — fully rounded, in-month only
      cellVisual = Center(child: indicator(c.brand.primaryBold));
    } else if (!_isOutside && _isToday && !isDisabled) {
      // Today border
      cellVisual = Center(
        child: indicator(
          isPressed ? c.bg.secondary : Colors.transparent,
          border: Border.all(color: c.brand.primary, width: 1.5),
        ),
      );
    } else {
      // Normal / outside / disabled / pressed
      cellVisual = Center(
        child: indicator(
          isPressed && !isDisabled ? c.bg.secondary : Colors.transparent,
        ),
      );
    }

    if (isDisabled) {
      return MouseRegion(
        cursor: SystemMouseCursors.forbidden,
        child: cellVisual,
      );
    }

    return MouseRegion(
      cursor: SystemMouseCursors.click,
      child: GestureDetector(
        // opaque so the full cell width is tappable even with centered indicator
        behavior: HitTestBehavior.opaque,
        onTap: () => onTap?.call(date),
        onTapDown: (_) => onPressChanged(date, true),
        onTapUp: (_) => onPressChanged(date, false),
        onTapCancel: () => onPressChanged(date, false),
        child: cellVisual,
      ),
    );
  }
}

import 'package:btech_tokens/btech_tokens.dart';
import '../../button/button.types.dart';
import '../../button/button.widget.dart';
import 'package:btech_ui/src/components/organisms/calendar/calendar.types.dart';
