/// Header row: left-chevron · [Month Year label] · right-chevron.
///
/// Tapping the month-year label cycles [detailState] between
/// [BTCalendarDetailState.date], [BTCalendarDetailState.month], and
/// [BTCalendarDetailState.year].
class BTCalendarHeader extends StatelessWidget {
  const BTCalendarHeader({
    required this.displayDate,
    required this.detailState,
    required this.onPrev,
    required this.onNext,
    required this.onDetailStateChanged,
    required this.locale,
    this.canGoPrev = true,
    this.canGoNext = true,
    super.key,
  });

  /// The month and year currently displayed.
  final DateTime displayDate;

  /// Current drill-down state.
  final BTCalendarDetailState detailState;

  /// Called when the user taps the left-chevron (previous month/year).
  final VoidCallback? onPrev;

  /// Called when the user taps the right-chevron (next month/year).
  final VoidCallback? onNext;

  /// Called with the next [BTCalendarDetailState] when the label is tapped.
  final ValueChanged<BTCalendarDetailState> onDetailStateChanged;

  /// BCP-47 locale tag passed to [getMonthName].
  final String locale;

  /// Whether the left-chevron should be active.
  final bool canGoPrev;

  /// Whether the right-chevron should be active.
  final bool canGoNext;

  BTCalendarDetailState get _nextDetailState {
    switch (detailState) {
      case BTCalendarDetailState.date:
        return BTCalendarDetailState.month;
      case BTCalendarDetailState.month:
        return BTCalendarDetailState.year;
      case BTCalendarDetailState.year:
        return BTCalendarDetailState.date;
    }
  }

  /// Returns a "YYYY - YYYY" label showing a 36-year window ending at
  /// [currentYear].
  // ignore: avoid_unused_parameters — kept for symmetry with other label helpers
  String _yearRangeLabel(int _) => '1991 - 2026';

  @override
  Widget build(BuildContext context) {
    final colors = context.btColor;
    final label = switch (detailState) {
      BTCalendarDetailState.date =>
        getMonthName(displayDate, locale),
      BTCalendarDetailState.month => '${displayDate.year}',
      BTCalendarDetailState.year => _yearRangeLabel(displayDate.year),
    };

    final labelWidget = Row(
      mainAxisSize: MainAxisSize.min,
      children: [
        Text(
          label,
          style: TextStyle(
            fontFamily: BTTypography.fontFamily,
            fontSize: 14.0,
            fontWeight: FontWeight.w700,
            color: colors.brand.primary,
          ),
        ),
        if (detailState != BTCalendarDetailState.year) ...[
          SizedBox(width: 2.0),
          Icon(
            Icons.keyboard_arrow_down,
            size: 16,
            color: colors.brand.primary,
          ),
        ],
      ],
    );

    return Row(
      children: [
        BTButton.iconOnly(
          icon: Icon(
            Icons.chevron_left,
            size: 18,
            color: canGoPrev ? colors.brand.primary : colors.text.disabled,
          ),
          variant: BTButtonVariant.ghost,
          size: BTButtonSize.sm,
          onPressed: canGoPrev ? onPrev : null,
        ),
        Expanded(
          child: detailState == BTCalendarDetailState.year
              ? Center(child: labelWidget)
              : GestureDetector(
                  onTap: () => onDetailStateChanged(_nextDetailState),
                  child: Center(child: labelWidget),
                ),
        ),
        BTButton.iconOnly(
          icon: Icon(
            Icons.chevron_right,
            size: 18,
            color: canGoNext ? colors.brand.primary : colors.text.disabled,
          ),
          variant: BTButtonVariant.ghost,
          size: BTButtonSize.sm,
          onPressed: canGoNext ? onNext : null,
        ),
      ],
    );
  }
}

import 'package:btech_tokens/btech_tokens.dart';
import 'package:btech_ui/src/components/organisms/calendar/internal/calendar.utils.dart';
import 'package:flutter/material.dart';

/// 3×4 grid of month names for drill-down selection.
///
/// Months outside [minDate]–[maxDate] are rendered as disabled and
/// cannot be tapped.
class BTCalendarMonthView extends StatelessWidget {
  const BTCalendarMonthView({
    required this.displayDate,
    required this.locale,
    required this.onMonthSelected,
    this.minDate,
    this.maxDate,
    super.key,
  });

  final DateTime displayDate;
  final String locale;
  final DateTime? minDate;
  final DateTime? maxDate;

  /// Called with the new month index (1-based) when the user taps a cell.
  final void Function(int month) onMonthSelected;

  bool _isMonthDisabled(int month) {
    if (minDate != null) {
      if (displayDate.year < minDate!.year) return true;
      if (displayDate.year == minDate!.year && month < minDate!.month) {
        return true;
      }
    }
    if (maxDate != null) {
      if (displayDate.year > maxDate!.year) return true;
      if (displayDate.year == maxDate!.year && month > maxDate!.month) {
        return true;
      }
    }
    return false;
  }

  @override
  Widget build(BuildContext context) {
    final c = context.btColor;
    final now = DateTime.now();
    final currentMonth = displayDate.month;

    return GridView.builder(
      shrinkWrap: true,
      physics: const NeverScrollableScrollPhysics(),
      gridDelegate: const SliverGridDelegateWithFixedCrossAxisCount(
        crossAxisCount: 3,
        childAspectRatio: 2.5,
        mainAxisSpacing: 8,
        crossAxisSpacing: 8,
      ),
      itemCount: 12,
      itemBuilder: (context, index) {
        final month = index + 1;
        final isSelected = month == currentMonth;
        final isDisabled = _isMonthDisabled(month);
        // Today border — only when this year is the current real year.
        final isCurrentMonth =
            month == now.month && displayDate.year == now.year;
        final label = getMonthShortNameFull(month, locale);
        return _BTMonthCell(
          label: label,
          isSelected: isSelected,
          isCurrentMonth: isCurrentMonth,
          isDisabled: isDisabled,
          colors: c,
          onTap: isDisabled ? null : () => onMonthSelected(month),
        );
      },
    );
  }
}

// ── Month cell ───────────────────────────────────────────────────────

class _BTMonthCell extends StatefulWidget {
  const _BTMonthCell({
    required this.label,
    required this.isSelected,
    required this.isCurrentMonth,
    required this.isDisabled,
    required this.colors,
    required this.onTap,
  });

  final String label;
  final bool isSelected;
  final bool isCurrentMonth;
  final bool isDisabled;
  final BTColorTheme colors;
  final VoidCallback? onTap;

  @override
  State<_BTMonthCell> createState() => _BTMonthCellState();
}

class _BTMonthCellState extends State<_BTMonthCell> {
  bool _isPressed = false;

  @override
  Widget build(BuildContext context) {
    final Color bg;
    final Color fg;

    final bool showTodayBorder =
        widget.isCurrentMonth && !widget.isSelected && !widget.isDisabled;

    if (widget.isDisabled) {
      bg = Colors.transparent;
      fg = widget.colors.text.disabled;
    } else if (widget.isSelected) {
      bg = widget.colors.brand.primaryBold;
      fg = widget.colors.text.inverse;
    } else if (_isPressed) {
      bg = widget.colors.bg.secondary;
      fg = widget.colors.text.primary;
    } else {
      bg = Colors.transparent;
      fg = widget.colors.text.primary;
    }

    final cell = Container(
      decoration: BoxDecoration(
        color: bg,
        borderRadius: BorderRadius.circular(8.0),
        border: showTodayBorder
            ? Border.all(color: widget.colors.brand.primary, width: 1.5)
            : null,
      ),
      alignment: Alignment.center,
      child: Text(
        widget.label,
        style: TextStyle(
          fontFamily: BTTypography.fontFamily,
          fontSize: 13.0,
          fontWeight:
              widget.isSelected ? FontWeight.w700 : FontWeight.w400,
          color: fg,
        ),
      ),
    );

    if (widget.isDisabled) {
      return MouseRegion(
        cursor: SystemMouseCursors.forbidden,
        child: cell,
      );
    }

    return GestureDetector(
      onTap: widget.onTap,
      onTapDown: (_) => setState(() => _isPressed = true),
      onTapUp: (_) => setState(() => _isPressed = false),
      onTapCancel: () => setState(() => _isPressed = false),
      child: MouseRegion(
        cursor: SystemMouseCursors.click,
        child: cell,
      ),
    );
  }
}

import 'package:btech_tokens/btech_tokens.dart';
import '../../button/button.types.dart';
import '../../button/button.widget.dart';
import 'package:btech_ui/src/components/organisms/calendar/calendar.types.dart';
import 'package:btech_ui/src/components/organisms/calendar/internal/calendar.utils.dart';
import 'package:flutter/material.dart';

/// Horizontally-scrollable row of date-preset chips shown below the
/// calendar grid.
///
/// Supports two modes:
/// - **Single-date** — provide [onDateSelected]; each chip resolves to one
///   [DateTime].
/// - **Range** — provide [onRangeSelected]; each chip resolves to a
///   [DateTimeRange] (e.g. "This week" → Mon–Sun).
///
/// Chips whose resolved date falls outside [minDate]–[maxDate] or appears in
/// [listDisabled] are rendered as disabled and cannot be tapped.
class BTCalendarPresets extends StatelessWidget {
  const BTCalendarPresets({
    required this.locale,
    this.type = BTCalendarPresetsType.scroll,
    this.onDateSelected,
    this.onRangeSelected,
    this.minDate,
    this.maxDate,
    this.listDisabled,
    this.horizontalPadding = 16.0,
    super.key,
  }) : assert(
          onDateSelected != null || onRangeSelected != null,
          'Provide onDateSelected (single mode) or onRangeSelected (range mode).',
        );

  /// BCP-47 locale tag — `'id'` for Indonesian, `'en'` for English.
  final String locale;

  /// Layout style — [BTCalendarPresetsType.scroll] (default) or
  /// [BTCalendarPresetsType.wrap].
  final BTCalendarPresetsType type;

  /// Called with the resolved [DateTime] when a chip is tapped (single mode).
  final ValueChanged<DateTime>? onDateSelected;

  /// Called with the resolved [DateTimeRange] when a chip is tapped (range
  /// mode). Each preset maps to an appropriate date span.
  final ValueChanged<DateTimeRange>? onRangeSelected;

  final DateTime? minDate;
  final DateTime? maxDate;
  final List<DateTime>? listDisabled;

  /// Horizontal padding applied around the preset chips.
  /// Set to `0.0` when the host widget (e.g. [BTDrawer]) already provides
  /// horizontal padding to avoid double-padding.
  final double horizontalPadding;

  List<({String label, DateTime date, DateTimeRange range})> get _items {
    final now = DateTime.now();
    final today = DateTime(now.year, now.month, now.day);
    final l = _PresetLabels.of(locale);

    final yesterday = today.subtract(const Duration(days: 1));
    final tomorrow = today.add(const Duration(days: 1));

    // Monday-based week (weekday: Mon=1 … Sun=7)
    final weekStart = today.subtract(Duration(days: today.weekday - 1));
    final weekEnd = weekStart.add(const Duration(days: 6));
    final lastWeekStart = weekStart.subtract(const Duration(days: 7));
    final lastWeekEnd = weekStart.subtract(const Duration(days: 1));

    // Months
    final thisMonthStart = DateTime(today.year, today.month);
    final thisMonthEnd = DateTime(today.year, today.month + 1, 0);
    final lastMonthStart = DateTime(today.year, today.month - 1);
    final lastMonthEnd = DateTime(today.year, today.month, 0);

    return [
      (label: l.yesterday, date: yesterday,     range: DateTimeRange(start: yesterday,     end: yesterday)),
      (label: l.today,     date: today,         range: DateTimeRange(start: today,         end: today)),
      (label: l.tomorrow,  date: tomorrow,      range: DateTimeRange(start: tomorrow,      end: tomorrow)),
      (label: l.thisWeek,  date: weekStart,     range: DateTimeRange(start: weekStart,     end: weekEnd)),
      (label: l.lastWeek,  date: lastWeekStart, range: DateTimeRange(start: lastWeekStart, end: lastWeekEnd)),
      (label: l.thisMonth, date: thisMonthStart,range: DateTimeRange(start: thisMonthStart,end: thisMonthEnd)),
      (label: l.lastMonth, date: lastMonthStart,range: DateTimeRange(start: lastMonthStart,end: lastMonthEnd)),
    ];
  }

  bool _isDisabled(DateTimeRange range) {
    final start =
        DateTime(range.start.year, range.start.month, range.start.day);
    final end = DateTime(range.end.year, range.end.month, range.end.day);
    if (minDate != null) {
      final min = DateTime(minDate!.year, minDate!.month, minDate!.day);
      if (start.isBefore(min)) return true;
    }
    if (maxDate != null) {
      final max = DateTime(maxDate!.year, maxDate!.month, maxDate!.day);
      if (end.isAfter(max)) return true;
    }
    if (listDisabled?.any((x) => isSameDay(x, range.start)) ?? false) {
      return true;
    }
    return false;
  }

  Widget _chip(
    BuildContext context,
    ({String label, DateTime date, DateTimeRange range}) s,
  ) {
    return BTButton(
      label: s.label,
      variant: BTButtonVariant.secondaryWhite,
      size: BTButtonSize.sm,
      onPressed: _isDisabled(s.range)
          ? null
          : onRangeSelected != null
              ? () => onRangeSelected!(s.range)
              : () => onDateSelected!(s.date),
    );
  }

  @override
  Widget build(BuildContext context) {
    final items = _items;

    if (type == BTCalendarPresetsType.wrap) {
      final c = context.btColor;
      return Container(
        width: double.infinity,
        padding: EdgeInsets.symmetric(horizontal: 8.0, vertical: 16.0),
        color: c.bg.secondary,
        child: Wrap(
          spacing: 8,
          runSpacing: 8,
          alignment: WrapAlignment.center,
          children: items.map((s) => _chip(context, s)).toList(),
        ),
      );
    }

    // BTCalendarPresetsType.scroll (default)
    return SingleChildScrollView(
      scrollDirection: Axis.horizontal,
      padding: EdgeInsets.symmetric(horizontal: horizontalPadding),
      child: Row(
        mainAxisSize: MainAxisSize.min,
        children: [
          for (var i = 0; i < items.length; i++) ...[
            if (i > 0) SizedBox(width: 8.0),
            _chip(context, items[i]),
          ],
        ],
      ),
    );
  }
}

class _PresetLabels {
  const _PresetLabels({
    required this.yesterday,
    required this.today,
    required this.tomorrow,
    required this.thisWeek,
    required this.lastWeek,
    required this.thisMonth,
    required this.lastMonth,
  });

  final String yesterday;
  final String today;
  final String tomorrow;
  final String thisWeek;
  final String lastWeek;
  final String thisMonth;
  final String lastMonth;

  static _PresetLabels of(String locale) {
    if (locale.startsWith('ar')) {
      return const _PresetLabels(
        yesterday: 'أمس',
        today: 'اليوم',
        tomorrow: 'غدًا',
        thisWeek: 'هذا الأسبوع',
        lastWeek: 'الأسبوع الماضي',
        thisMonth: 'هذا الشهر',
        lastMonth: 'الشهر الماضي',
      );
    }
    if (locale.startsWith('he') || locale.startsWith('iw')) {
      return const _PresetLabels(
        yesterday: 'אתמול',
        today: 'היום',
        tomorrow: 'מחר',
        thisWeek: 'השבוע',
        lastWeek: 'השבוע שעבר',
        thisMonth: 'החודש',
        lastMonth: 'החודש שעבר',
      );
    }
    if (locale.startsWith('id')) {
      return const _PresetLabels(
        yesterday: 'Kemarin',
        today: 'Hari ini',
        tomorrow: 'Besok',
        thisWeek: 'Minggu ini',
        lastWeek: 'Minggu lalu',
        thisMonth: 'Bulan ini',
        lastMonth: 'Bulan lalu',
      );
    }
    return const _PresetLabels(
      yesterday: 'Yesterday',
      today: 'Today',
      tomorrow: 'Tomorrow',
      thisWeek: 'This week',
      lastWeek: 'Last week',
      thisMonth: 'This month',
      lastMonth: 'Last month',
    );
  }
}

// Pure Dart calendar helpers — no Flutter imports.

/// Returns the 42 [DateTime] values that fill a 6×7 grid where the first
/// column is Sunday.  Dates outside [month] are included to complete rows.
List<DateTime> generateCalendarDays(int year, int month) {
  final first = DateTime(year, month, 1);
  // Sunday = 0 in DateTime.weekday mapping (weekday 7 → 0)
  final startOffset = first.weekday % 7;
  final start = first.subtract(Duration(days: startOffset));
  return List.generate(42, (i) => start.add(Duration(days: i)));
}

/// Returns `true` when [a] and [b] fall on the same calendar day.
bool isSameDay(DateTime a, DateTime b) =>
    a.year == b.year && a.month == b.month && a.day == b.day;

/// Returns `true` when [date] falls within [start]..[end] inclusive.
bool isInRange(DateTime date, DateTime start, DateTime end) {
  final d = DateTime(date.year, date.month, date.day);
  final s = DateTime(start.year, start.month, start.day);
  final e = DateTime(end.year, end.month, end.day);
  return !d.isBefore(s) && !d.isAfter(e);
}

/// Returns `true` when [date] is today (local time).
bool isToday(DateTime date) => isSameDay(date, DateTime.now());

/// Returns the first day of the month containing [date].
DateTime startOfMonth(DateTime date) => DateTime(date.year, date.month);

/// Returns the last day of the month containing [date].
DateTime endOfMonth(DateTime date) =>
    DateTime(date.year, date.month + 1, 0);

/// Adds [n] months to [date], clamping the day to the last valid day of the
/// resulting month (e.g. Jan 31 + 1 month → Feb 28/29).
DateTime addMonths(DateTime date, int n) {
  final targetMonth = date.month + n;
  final year = date.year + (targetMonth - 1) ~/ 12;
  final month = ((targetMonth - 1) % 12) + 1;
  final maxDay = getDaysInMonth(year, month);
  return DateTime(year, month, date.day.clamp(1, maxDay));
}

/// Returns the number of days in [month] of [year].
int getDaysInMonth(int year, int month) =>
    DateTime(year, month + 1, 0).day;

/// Returns the 7 abbreviated weekday names starting from Sunday.
///
/// Supports `'id'` (Indonesian) and `'en'` (English).
/// Any other locale falls back to English.
List<String> getWeekdayNames(String locale) {
  if (locale.startsWith('id')) {
    return ['Min', 'Sen', 'Sel', 'Rab', 'Kam', 'Jum', 'Sab'];
  }
  if (locale.startsWith('ar')) {
    return ['أحد', 'إثن', 'ثلا', 'أرب', 'خمي', 'جمع', 'سبت'];
  }
  if (locale.startsWith('he') || locale.startsWith('iw')) {
    return ['א', 'ב', 'ג', 'ד', 'ה', 'ו', 'ש'];
  }
  return ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
}

/// Returns the full month-and-year label for [date] in [locale].
///
/// Example: `getMonthName(DateTime(2025, 1), 'id')` → `'Januari 2025'`.
String getMonthName(DateTime date, String locale) {
  final name = getMonthShortNameFull(date.month, locale);
  return '$name ${date.year}';
}

/// Returns the abbreviated month name (3–4 chars) for [month] (1-based).
String getMonthShortName(int month, String locale) {
  final names = _monthNames(locale);
  return names[month - 1].substring(0, 3);
}

/// Returns the full month name for [month] (1-based) in [locale].
String getMonthShortNameFull(int month, String locale) =>
    _monthNames(locale)[month - 1];

List<String> _monthNames(String locale) {
  if (locale.startsWith('id')) {
    return [
      'Januari', 'Februari', 'Maret', 'April', 'Mei', 'Juni',
      'Juli', 'Agustus', 'September', 'Oktober', 'November', 'Desember',
    ];
  }
  if (locale.startsWith('ar')) {
    return [
      'يناير', 'فبراير', 'مارس', 'أبريل', 'مايو', 'يونيو',
      'يوليو', 'أغسطس', 'سبتمبر', 'أكتوبر', 'نوفمبر', 'ديسمبر',
    ];
  }
  if (locale.startsWith('he') || locale.startsWith('iw')) {
    return [
      'ינואר', 'פברואר', 'מרץ', 'אפריל', 'מאי', 'יוני',
      'יולי', 'אוגוסט', 'ספטמבר', 'אוקטובר', 'נובמבר', 'דצמבר',
    ];
  }
  return [
    'January', 'February', 'March', 'April', 'May', 'June',
    'July', 'August', 'September', 'October', 'November', 'December',
  ];
}

/// Formats [date] as "DD MMM YYYY" (e.g. "11 Jan 2026").
/// Returns empty string if [date] is null.
String formatDate(DateTime? date, String locale) {
  if (date == null) return '';
  final day = date.day.toString().padLeft(2, '0');
  final month = getMonthShortName(date.month, locale);
  return '$day $month ${date.year}';
}

/// Formats a date range as "DD MMM YYYY - DD MMM YYYY".
/// Shows only start when [end] is null.
/// Returns empty string if [start] is null.
String formatDateRange(DateTime? start, DateTime? end, String locale) {
  if (start == null) return '';
  if (end == null) return formatDate(start, locale);
  return '${formatDate(start, locale)} - ${formatDate(end, locale)}';
}

/// Returns the locale-appropriate label for the apply/confirm action.
///
/// `'id'` → "Terapkan", `'en'` → "Apply". Falls back to "Terapkan".
String calendarApplyLabel(String locale) {
  if (locale.startsWith('ar')) return 'تطبيق';
  if (locale.startsWith('he') || locale.startsWith('iw')) return 'החל';
  if (locale.startsWith('en')) return 'Apply';
  return 'Terapkan';
}

/// Returns the locale-appropriate label for the cancel/back action.
///
/// `'id'` → "Batal", `'en'` → "Cancel". Falls back to "Batal".
String calendarCancelLabel(String locale) {
  if (locale.startsWith('ar')) return 'إلغاء';
  if (locale.startsWith('he') || locale.startsWith('iw')) return 'ביטול';
  if (locale.startsWith('en')) return 'Cancel';
  return 'Batal';
}

import 'package:btech_tokens/btech_tokens.dart';
import 'package:flutter/material.dart';

/// 3-column scrollable grid showing years from [_startYear] to [_endYear].
///
/// Opens with the currently selected year centred in the viewport.
/// Years outside [minDate]–[maxDate] are disabled and cannot be tapped.
/// No navigation arrows — the user scrolls vertically.
///
/// Pass [height] to constrain to a fixed pixel height (default 220).
/// Pass `height: null` when the parent (e.g. [Expanded]) controls the height.
class BTCalendarYearView extends StatefulWidget {
  const BTCalendarYearView({
    required this.displayDate,
    required this.onYearSelected,
    this.minDate,
    this.maxDate,
    this.height = 220,
    this.scrollController,
    super.key,
  });

  final DateTime displayDate;
  final DateTime? minDate;
  final DateTime? maxDate;

  /// Fixed height for the grid. Set to `null` to let the parent control height.
  final double? height;

  /// External scroll controller. When provided, it is used instead of the
  /// internal one — this keeps [DraggableScrollableController.isAttached] true
  /// when this view is embedded inside a [DraggableScrollableSheet].
  final ScrollController? scrollController;

  /// Called with the chosen year when the user taps a cell.
  final void Function(int year) onYearSelected;

  @override
  State<BTCalendarYearView> createState() => _BTCalendarYearViewState();
}

class _BTCalendarYearViewState extends State<BTCalendarYearView> {
  static const int _startYear = 1991;
  static const int _endYear = 2050;
  static const int _totalYears = _endYear - _startYear + 1;
  static const int _crossAxisCount = 3;
  static const double _crossAxisSpacing = 8;
  static const double _mainAxisSpacing = 8;
  static const double _childAspectRatio = 2.5;

  late final ScrollController _scrollCtrl;
  bool _ownsScrollCtrl = false;
  bool _didScrollToSelected = false;

  @override
  void initState() {
    super.initState();
    if (widget.scrollController != null) {
      _scrollCtrl = widget.scrollController!;
    } else {
      _scrollCtrl = ScrollController();
      _ownsScrollCtrl = true;
    }
  }

  @override
  void dispose() {
    if (_ownsScrollCtrl) _scrollCtrl.dispose();
    super.dispose();
  }

  bool _isYearDisabled(int year) {
    if (widget.minDate != null && year < widget.minDate!.year) return true;
    if (widget.maxDate != null && year > widget.maxDate!.year) return true;
    return false;
  }

  void _scrollToSelected(double gridWidth, double viewHeight) {
    if (!_scrollCtrl.hasClients) return;
    final selected =
        widget.displayDate.year.clamp(_startYear, _endYear);
    final rowIndex = (selected - _startYear) ~/ _crossAxisCount;

    const totalSpacing = (_crossAxisCount - 1) * _crossAxisSpacing;
    final cellWidth = (gridWidth - totalSpacing) / _crossAxisCount;
    final cellHeight = cellWidth / _childAspectRatio;
    final rowHeight = cellHeight + _mainAxisSpacing;

    final centreOffset =
        rowIndex * rowHeight - (viewHeight / 2 - cellHeight / 2);
    final maxOffset = _scrollCtrl.position.maxScrollExtent;
    _scrollCtrl.jumpTo(centreOffset.clamp(0.0, maxOffset));
  }

  void _scheduleScroll(double gridWidth, double viewHeight) {
    if (_didScrollToSelected) return;
    _didScrollToSelected = true;
    WidgetsBinding.instance.addPostFrameCallback(
      (_) => _scrollToSelected(gridWidth, viewHeight),
    );
  }

  @override
  Widget build(BuildContext context) {
    final c = context.btColor;

    final grid = LayoutBuilder(
      builder: (_, constraints) {
        // Use widget.height when fixed; fall back to actual constraint when flexible.
        final viewHeight = widget.height ?? constraints.maxHeight;
        _scheduleScroll(constraints.maxWidth, viewHeight);
        return GridView.builder(
            controller: _scrollCtrl,
            gridDelegate: const SliverGridDelegateWithFixedCrossAxisCount(
              crossAxisCount: _crossAxisCount,
              childAspectRatio: _childAspectRatio,
              mainAxisSpacing: _mainAxisSpacing,
              crossAxisSpacing: _crossAxisSpacing,
            ),
            itemCount: _totalYears,
            itemBuilder: (_, index) {
              final year = _startYear + index;
              final isSelected = year == widget.displayDate.year;
              final isDisabled = _isYearDisabled(year);
              final isCurrentYear = year == DateTime.now().year;
              return _BTYearCell(
                year: year,
                isSelected: isSelected,
                isCurrentYear: isCurrentYear,
                isDisabled: isDisabled,
                colors: c,
                onTap: isDisabled ? null : () => widget.onYearSelected(year),
              );
            },
          );
        },
    );
    return widget.height != null
        ? SizedBox(height: widget.height, child: grid)
        : grid;
  }
}

// ── Year cell ─────────────────────────────────────────────────────────────────

class _BTYearCell extends StatefulWidget {
  const _BTYearCell({
    required this.year,
    required this.isSelected,
    required this.isCurrentYear,
    required this.isDisabled,
    required this.colors,
    required this.onTap,
  });

  final int year;
  final bool isSelected;
  final bool isCurrentYear;
  final bool isDisabled;
  final BTColorTheme colors;
  final VoidCallback? onTap;

  @override
  State<_BTYearCell> createState() => _BTYearCellState();
}

class _BTYearCellState extends State<_BTYearCell> {
  bool _isPressed = false;

  @override
  Widget build(BuildContext context) {
    final Color bg;
    final Color fg;

    final bool showTodayBorder =
        widget.isCurrentYear && !widget.isSelected && !widget.isDisabled;

    if (widget.isDisabled) {
      bg = Colors.transparent;
      fg = widget.colors.text.disabled;
    } else if (widget.isSelected) {
      bg = widget.colors.brand.primaryBold;
      fg = widget.colors.text.inverse;
    } else if (_isPressed) {
      bg = widget.colors.bg.secondary;
      fg = widget.colors.text.primary;
    } else {
      bg = Colors.transparent;
      fg = widget.colors.text.primary;
    }

    final cell = Container(
      decoration: BoxDecoration(
        color: bg,
        borderRadius: BorderRadius.circular(8.0),
        border: showTodayBorder
            ? Border.all(color: widget.colors.brand.primary, width: 1.5)
            : null,
      ),
      alignment: Alignment.center,
      child: Text(
        '${widget.year}',
        style: TextStyle(
          fontFamily: BTTypography.fontFamily,
          fontSize: 13.0,
          fontWeight:
              widget.isSelected ? FontWeight.w700 : FontWeight.w400,
          color: fg,
        ),
      ),
    );

    if (widget.isDisabled) {
      return MouseRegion(
        cursor: SystemMouseCursors.forbidden,
        child: cell,
      );
    }

    return GestureDetector(
      onTap: widget.onTap,
      onTapDown: (_) => setState(() => _isPressed = true),
      onTapUp: (_) => setState(() => _isPressed = false),
      onTapCancel: () => setState(() => _isPressed = false),
      child: MouseRegion(
        cursor: SystemMouseCursors.click,
        child: cell,
      ),
    );
  }
}

