/// Drum-roll time selector supporting 24-hour and 12-hour formats.
///
/// - [BTCalendarTimeVariant.hhMm] — HH : MM (24-h, 2 wheels)
/// - [BTCalendarTimeVariant.hhMmSs] — HH : MM : SS (24-h, 3 wheels)
/// - [BTCalendarTimeVariant.amPm] — H : MM + AM/PM wheel (12-h)
/// - [BTCalendarTimeVariant.amPmSs] — H : MM : SS + AM/PM wheel (12-h)
class BTTimePicker extends StatefulWidget {
  const BTTimePicker({
    this.initialTime,
    this.variant = BTCalendarTimeVariant.hhMm,
    this.onChanged,
    this.locale = 'id',
    this.showFooter = false,
    this.onApply,
    this.onCancel,
    this.topPadding = 24,
    this.stackedButtons = false,
    this.isEmbedded = false,
    super.key,
  });

  /// Time displayed when the widget first renders.
  final TimeOfDay? initialTime;

  /// Which columns to show.
  final BTCalendarTimeVariant variant;

  /// Called whenever the selected time changes.
  final ValueChanged<TimeOfDay>? onChanged;

  /// BCP-47 locale tag (reserved for future i18n use).
  final String locale;

  /// Show Apply / Cancel footer buttons inside the widget.
  final bool showFooter;

  /// Called when the user taps Apply.
  final VoidCallback? onApply;

  /// Called when the user taps Cancel.
  final VoidCallback? onCancel;

  /// Top padding above the time header. Default 24 for modal, use 8 for drawer.
  final double topPadding;

  /// Stack footer buttons vertically (Apply then Cancel). Default false (side-by-side).
  final bool stackedButtons;

  /// When true, removes horizontal and bottom padding — the host widget
  /// (e.g. [BTDrawer]) is expected to provide it.
  final bool isEmbedded;

  /// Show a time picker dialog or bottom sheet and return the selected [TimeOfDay].
  ///
  /// ```dart
  /// final t = await BTTimePicker.show(context, variant: BTCalendarTimeVariant.amPm);
  /// // drawer variant:
  /// final t = await BTTimePicker.show(context, type: BTCalendarShowType.drawer);
  /// ```
  static Future<TimeOfDay?> show(
    BuildContext context, {
    BTCalendarTimeVariant variant = BTCalendarTimeVariant.hhMm,
    TimeOfDay? initialTime,
    void Function(TimeOfDay)? onApply,
    VoidCallback? onCancel,
    BTCalendarShowType type = BTCalendarShowType.modal,
  }) {
    // ignore: prefer_final_locals — mutated in callback
    var picked = initialTime ?? TimeOfDay.now();

    if (type == BTCalendarShowType.drawer) {
      return BTDrawer.show<TimeOfDay?>(
        context,
        hasCloseIcon: false,
        hasFooter: true,
        primaryLabel: 'Terapkan',
        secondaryLabel: 'Batal',
        content: BTTimePicker(
          variant: variant,
          initialTime: initialTime,
          isEmbedded: true,
          topPadding: 8,
          onChanged: (t) => picked = t,
        ),
        onPrimary: () {
          onApply?.call(picked);
          Navigator.of(context).pop(picked);
        },
        onSecondary: () {
          onCancel?.call();
          Navigator.of(context).pop();
        },
      );
    }

    return showDialog<TimeOfDay>(
      context: context,
      barrierColor: Colors.black54,
      builder: (ctx) => Dialog(
        backgroundColor: Colors.transparent,
        insetPadding: EdgeInsets.symmetric(
          horizontal: 24.0,
          vertical: 40.0,
        ),
        child: Container(
          decoration: BoxDecoration(
            color: ctx.btColor.bg.primary,
            borderRadius: BorderRadius.circular(16.0),
          ),
          child: SafeArea(
            top: false,
            child: BTTimePicker(
              variant: variant,
              initialTime: initialTime,
              showFooter: true,
              onChanged: (t) => picked = t,
              onCancel: () {
                onCancel?.call();
                Navigator.of(ctx).pop();
              },
              onApply: () {
                onApply?.call(picked);
                Navigator.of(ctx).pop(picked);
              },
            ),
          ),
        ),
      ),
    );
  }

  @override
  State<BTTimePicker> createState() => _BTTimePickerState();
}

class _BTTimePickerState extends State<BTTimePicker> {
  late int _hour; // always 0-23 internally
  late int _minute;
  late int _second;
  late bool _isPm;

  bool get _is24h =>
      widget.variant == BTCalendarTimeVariant.hhMm ||
      widget.variant == BTCalendarTimeVariant.hhMmSs;

  bool get _hasSeconds =>
      widget.variant == BTCalendarTimeVariant.hhMmSs ||
      widget.variant == BTCalendarTimeVariant.amPmSs;

  @override
  void initState() {
    super.initState();
    final t = widget.initialTime ?? TimeOfDay.now();
    _hour = t.hour;
    _minute = t.minute;
    _second = 0;
    _isPm = t.period == DayPeriod.pm;
  }

  void _emit() {
    widget.onChanged?.call(TimeOfDay(hour: _hour, minute: _minute));
  }

  int get _displayHour =>
      _is24h ? _hour : (_hour % 12 == 0 ? 12 : _hour % 12);

  void _onHourChanged(int index) {
    setState(() {
      if (_is24h) {
        _hour = index;
      } else {
        // Convert 12-h index (0=1, ..., 11=12) to 24-h
        final h12 = index + 1; // 1..12
        _hour = _isPm ? (h12 % 12) + 12 : h12 % 12;
      }
    });
    _emit();
  }

  void _onMinuteChanged(int index) {
    setState(() => _minute = index);
    _emit();
  }

  void _onSecondChanged(int index) {
    setState(() => _second = index);
    _emit();
  }

  void _onAmPmChanged(int index) {
    setState(() {
      _isPm = index == 1;
      // Re-sync _hour to the new period
      final h12 = _hour % 12 == 0 ? 12 : _hour % 12;
      _hour = _isPm ? (h12 % 12) + 12 : h12 % 12;
    });
    _emit();
  }

  List<String> get _hourItems => _is24h
      ? List.generate(24, (i) => i.toString().padLeft(2, '0'))
      : List.generate(12, (i) => (i + 1).toString().padLeft(2, '0'));

  List<String> get _minuteItems =>
      List.generate(60, (i) => i.toString().padLeft(2, '0'));

  List<String> get _secondItems =>
      List.generate(60, (i) => i.toString().padLeft(2, '0'));

  /// The live time label shown at the top (e.g. "08:30" or "08:30 AM").
  String get _headerLabel {
    final h = _is24h
        ? _hour.toString().padLeft(2, '0')
        : _displayHour.toString().padLeft(2, '0');
    final m = _minute.toString().padLeft(2, '0');
    final s = _hasSeconds ? ':${_second.toString().padLeft(2, '0')}' : '';
    final period = _is24h ? '' : (_isPm ? ' PM' : ' AM');
    return '$h:$m$s$period';
  }

  static const double _wheelHeight = BTTimeWheel.kWheelHeight;
  static const double _selectionTop =
      (BTTimeWheel.kWheelHeight - BTTimeWheel.kSelectionBarHeight) / 2;
  static const double _selectionHeight = BTTimeWheel.kSelectionBarHeight;

  @override
  Widget build(BuildContext context) {
    final c = context.btColor;
    final hourIndex = _is24h ? _hour : (_displayHour - 1).clamp(0, 11);
    final amPmIndex = _isPm ? 1 : 0;

    return Padding(
      padding: widget.isEmbedded
          ? EdgeInsets.fromLTRB(0, widget.topPadding, 0, 0)
          : EdgeInsets.fromLTRB(16.0, widget.topPadding, 16.0, 16.0),
      child: Column(
        mainAxisSize: MainAxisSize.min,
        children: [
          // Header: live time preview (fontSize.sm = 14px per Figma node 2579-14226)
          Padding(
            padding: EdgeInsets.only(bottom: 16.0),
            child: Text(
              _headerLabel,
              style: TextStyle(
                fontFamily: BTTypography.fontFamily,
                fontSize: 14.0,
                fontWeight: FontWeight.w700,
                color: c.brand.primary,
              ),
            ),
          ),
          // Wheel area with full-width selection highlight
          SizedBox(
            height: _wheelHeight,
            child: Stack(
              alignment: Alignment.center,
              children: [
                // Full-width selection highlight box (behind all wheels)
                Positioned(
                  top: _selectionTop,
                  left: 0,
                  right: 0,
                  height: _selectionHeight,
                  child: Container(
                    decoration: BoxDecoration(
                      color: c.bg.subtle,
                      borderRadius: BorderRadius.circular(8.0),
                    ),
                  ),
                ),
                // Wheels row — equal columns, each wheel fixed 64px wide
                // so the remaining column space is margin around the wheel.
                Row(
                  crossAxisAlignment: CrossAxisAlignment.center,
                  children: [
                    Expanded(
                      child: Center(
                        child: SizedBox(
                          width: 64.0,
                          child: BTTimeWheel(
                            key: ValueKey(_is24h),
                            items: _hourItems,
                            initialIndex: hourIndex,
                            onChanged: _onHourChanged,
                          ),
                        ),
                      ),
                    ),
                    _separator(context),
                    Expanded(
                      child: Center(
                        child: SizedBox(
                          width: 64.0,
                          child: BTTimeWheel(
                            items: _minuteItems,
                            initialIndex: _minute,
                            onChanged: _onMinuteChanged,
                          ),
                        ),
                      ),
                    ),
                    if (_hasSeconds) ...[
                      _separator(context),
                      Expanded(
                        child: Center(
                          child: SizedBox(
                            width: 64,
                            child: BTTimeWheel(
                              items: _secondItems,
                              initialIndex: _second,
                              onChanged: _onSecondChanged,
                            ),
                          ),
                        ),
                      ),
                    ],
                    if (!_is24h) ...[
                      SizedBox(width: 8.0),
                      SizedBox(
                        width: 56.0,
                        child: BTTimeWheel(
                          items: const ['AM', 'PM'],
                          initialIndex: amPmIndex,
                          onChanged: _onAmPmChanged,
                          looping: false,
                        ),
                      ),
                    ],
                  ],
                ),
              ],
            ),
          ),
          if (widget.showFooter) ...[
            SizedBox(height: 12.0),
            if (widget.stackedButtons) ...[
              SizedBox(
                width: double.infinity,
                child: BTButton(
                  label: 'Terapkan',

                  onPressed: widget.onApply,
                ),
              ),
              SizedBox(height: 8.0),
              SizedBox(
                width: double.infinity,
                child: BTButton(
                  label: 'Batal',
                  variant: BTButtonVariant.secondaryLight,

                  onPressed: widget.onCancel,
                ),
              ),
            ] else
              Row(
                children: [
                  Expanded(
                    child: BTButton(
                      label: 'Batal',
                      variant: BTButtonVariant.secondaryLight,
                      onPressed: widget.onCancel,
                    ),
                  ),
                  SizedBox(width: 8.0),
                  Expanded(
                    child: BTButton(
                      label: 'Terapkan',
                      onPressed: widget.onApply,
                    ),
                  ),
                ],
              ),
          ],
        ],
      ),
    );
  }

  Widget _separator(BuildContext context) => Padding(
        padding: EdgeInsets.symmetric(horizontal: 8.0),
        child: Text(
          ':',
          style: TextStyle(
            fontFamily: BTTypography.fontFamily,
            fontSize: 18.0,
            fontWeight: FontWeight.w700,
            color: context.btColor.text.primary,
          ),
        ),
      );
}
